const https = require('https');
const urlMod = require('url');
function httpReq(method, rawUrl, headers, postBody) {
  return new Promise((resolve, reject) => {
    const parsed = urlMod.parse(rawUrl);
    const opts = { hostname: parsed.hostname, path: parsed.path, method: method, headers: headers || {} };
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        let json = null;
        try { json = JSON.parse(body); } catch(e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: json, text: body });
      });
    });
    req.on('error', reject);
    if (postBody) req.write(typeof postBody === 'string' ? postBody : JSON.stringify(postBody));
    req.end();
  });
}

// Signoff Receiver: processes crew sign-off form submissions
// Updates GHL opportunity custom fields and creates ClickUp record
const GHL_TOKEN = '{{ghl_token}}';
const LOCATION_ID = '{{ghl_location_id}}';
const CLICKUP_TOKEN = '{{clickup_token}}';
const COMPLETED_LIST = '{{clickup_list_completed}}';
const GHL_BASE = 'https://services.leadconnectorhq.com';
const CU_BASE = 'https://api.clickup.com/api/v2';
const GHL_HEADERS = { 'Authorization': `Bearer ${GHL_TOKEN}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };
const CU_HEADERS = { 'Authorization': CLICKUP_TOKEN, 'Content-Type': 'application/json' };

const body = $input.first().json;
const oppId = body.opp_id;
const jobName = body.job_name || 'Unknown Job';
const crew = body.crew || '';
const goback = body.goback === 'true' || body.goback === true;
const notes = body.notes || '';

if (!oppId) return [{ json: { status: 'error', message: 'No opp_id in form data' } }];

// Update GHL opportunity custom fields
const updateFields = [
  { id: '{{ghl_cf_signed_off}}', value: true },
  { id: '{{ghl_cf_photos_uploaded}}', value: true },
  { id: '{{ghl_cf_goback_required}}', value: goback },
  { id: '{{ghl_cf_completion_date}}', value: new Date().toISOString() }
];

await fetch(`${GHL_BASE}/opportunities/${oppId}`, {
  method: 'PUT',
  headers: GHL_HEADERS,
  body: JSON.stringify({ customFields: updateFields })
});

// Create completion record in ClickUp
const taskBody = {
  name: `Completed: ${jobName}`,
  description: `**Sign-Off Record**\nCrew: ${crew}\nGo-Back Required: ${goback ? 'YES' : 'No'}\nNotes: ${notes}\nGHL Opportunity: ${oppId}\nSubmitted: ${new Date().toISOString()}`,
  status: goback ? 'review' : 'complete',
  priority: goback ? 1 : 3
};

const task = await httpReq('POST', `${CU_BASE}/list/${COMPLETED_LIST}/task`, CU_HEADERS, JSON.stringify(taskBody)
);
const taskData = await task.json;

return [{ json: { status: 'ok', opp_id: oppId, goback, clickup_task_id: taskData.id } }];
